import{_ as a,c as i,o,a1 as t}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Inicio Rápido: Instalación y Configuración de Antigravity Auth | OpenCode","description":"Aprende a instalar y configurar el plugin Antigravity Auth. Completa la autenticación OAuth de Google en 10 minutos, envía tu primera solicitud de modelo y verifica el acceso exitoso a los modelos Claude y Gemini.","frontmatter":{"title":"Inicio Rápido: Instalación y Configuración de Antigravity Auth | OpenCode","sidebarTitle":"En Marcha en 10 Minutos","subtitle":"Inicio Rápido: Instalación y Configuración de Antigravity Auth","description":"Aprende a instalar y configurar el plugin Antigravity Auth. Completa la autenticación OAuth de Google en 10 minutos, envía tu primera solicitud de modelo y verifica el acceso exitoso a los modelos Claude y Gemini.","order":1},"headers":[],"relativePath":"es/NoeFabris/opencode-antigravity-auth/start/index.md","filePath":"es/NoeFabris/opencode-antigravity-auth/start/index.md"}'),n={name:"es/NoeFabris/opencode-antigravity-auth/start/index.md"};function l(r,e,s,d,c,u){return o(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="inicio-rapido" tabindex="-1">Inicio Rápido <a class="header-anchor" href="#inicio-rapido" aria-label="Permalink to &quot;Inicio Rápido&quot;">​</a></h1><p>Este capítulo te ayuda a comenzar desde cero con el plugin Antigravity Auth. Conocerás el valor central del plugin, completarás la instalación y la autenticación OAuth, y enviarás tu primera solicitud de modelo para verificar que la configuración es exitosa.</p><h2 id="ruta-de-aprendizaje" tabindex="-1">Ruta de Aprendizaje <a class="header-anchor" href="#ruta-de-aprendizaje" aria-label="Permalink to &quot;Ruta de Aprendizaje&quot;">​</a></h2><p>Sigue este orden de aprendizaje, cada paso se basa en el anterior:</p><h3 id="_1-introduccion-al-plugin" tabindex="-1">1. <a href="./what-is-antigravity-auth/">Introducción al Plugin</a> <a class="header-anchor" href="#_1-introduccion-al-plugin" aria-label="Permalink to &quot;1. [Introducción al Plugin](./what-is-antigravity-auth/)&quot;">​</a></h3><p>Conoce el valor central del plugin Antigravity Auth, los escenarios de uso y las advertencias de riesgo.</p><ul><li>Determina si el plugin se adapta a tu caso de uso</li><li>Conoce los modelos de IA compatibles (Claude Opus 4.5, Sonnet 4.5, Gemini 3 Pro/Flash)</li><li>Comprende los riesgos y precauciones de uso</li></ul><h3 id="_2-instalacion-rapida" tabindex="-1">2. <a href="./quick-install/">Instalación Rápida</a> <a class="header-anchor" href="#_2-instalacion-rapida" aria-label="Permalink to &quot;2. [Instalación Rápida](./quick-install/)&quot;">​</a></h3><p>Completa la instalación del plugin y la primera autenticación en 5 minutos.</p><ul><li>Dos métodos de instalación (con asistente de IA / configuración manual)</li><li>Configuración de definiciones de modelo</li><li>Ejecución de la autenticación OAuth de Google</li></ul><h3 id="_3-autenticacion-oauth-2-0-pkce" tabindex="-1">3. <a href="./first-auth-login/">Autenticación OAuth 2.0 PKCE</a> <a class="header-anchor" href="#_3-autenticacion-oauth-2-0-pkce" aria-label="Permalink to &quot;3. [Autenticación OAuth 2.0 PKCE](./first-auth-login/)&quot;">​</a></h3><p>Comprende el flujo de autenticación OAuth 2.0 PKCE y completa el primer inicio de sesión.</p><ul><li>Entiende el mecanismo de seguridad de la autenticación PKCE</li><li>Completa el primer inicio de sesión para obtener permisos de acceso a la API</li><li>Conoce el manejo automatizado de la renovación de tokens</li></ul><h3 id="_4-primera-solicitud" tabindex="-1">4. <a href="./first-request/">Primera Solicitud</a> <a class="header-anchor" href="#_4-primera-solicitud" aria-label="Permalink to &quot;4. [Primera Solicitud](./first-request/)&quot;">​</a></h3><p>Envía la primera solicitud de modelo para verificar que la instalación es exitosa.</p><ul><li>Envía la primera solicitud de modelo Antigravity</li><li>Comprende los parámetros <code>--model</code> y <code>--variant</code></li><li>Soluciona errores comunes en solicitudes de modelo</li></ul><h2 id="requisitos-previos" tabindex="-1">Requisitos Previos <a class="header-anchor" href="#requisitos-previos" aria-label="Permalink to &quot;Requisitos Previos&quot;">​</a></h2><p>Antes de comenzar este capítulo, confirma:</p><ul><li>✅ OpenCode CLI instalado (comando <code>opencode</code> disponible)</li><li>✅ Cuenta de Google disponible (para autenticación OAuth)</li></ul><h2 id="siguiente-paso" tabindex="-1">Siguiente Paso <a class="header-anchor" href="#siguiente-paso" aria-label="Permalink to &quot;Siguiente Paso&quot;">​</a></h2><p>Después de completar el inicio rápido, puedes:</p><ul><li><strong><a href="./../platforms/available-models/">Conocer Modelos Disponibles</a></strong> — Explorar todos los modelos compatibles y sus configuraciones de variantes</li><li><strong><a href="./../advanced/multi-account-setup/">Configurar Múltiples Cuentas</a></strong> — Configurar varias cuentas de Google para agrupar cuotas</li><li><strong><a href="./../faq/common-auth-issues/">Problemas Comunes de Autenticación</a></strong> — Consultar la guía de solución de problemas cuando encuentres dificultades</li></ul>',22)])])}const h=a(n,[["render",l]]);export{m as __pageData,h as default};
